import React from 'react';
import { View, Text, TouchableOpacity, StyleSheet } from 'react-native';

export default function MessageBubble({ message, onToggleReaction }) {
  const currentUserId = message._currentUserId || '';
  const greenByMe = message.likedGreen?.some((u) => u.id === currentUserId);
  const redByMe = message.likedRed?.some((u) => u.id === currentUserId);

  return (
    <View style={styles.bubble}>
      <Text style={styles.author}>{message.author.name}</Text>
      <Text style={styles.text}>{message.text}</Text>
      <View style={styles.row}>
        <Text style={styles.time}>{new Date(message.createdAt).toLocaleString()}</Text>
        <View style={styles.reactions}>
          <TouchableOpacity onPress={() => onToggleReaction(message, 'green')} style={styles.reactBtn}>
            <Text style={{ color: greenByMe ? 'green' : '#333' }}>{greenByMe ? '💚' : '🤍'}</Text>
          </TouchableOpacity>
          <TouchableOpacity onPress={() => onToggleReaction(message, 'red')} style={styles.reactBtn}>
            <Text style={{ color: redByMe ? 'red' : '#333' }}>{redByMe ? '❤️' : '🤍'}</Text>
          </TouchableOpacity>
        </View>
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  bubble: { padding: 10, borderWidth: 1, borderColor: '#eee', borderRadius: 8, marginBottom: 8 },
  author: { fontWeight: '600' },
  text: { marginTop: 6, marginBottom: 6 },
  row: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' },
  time: { color: '#666', fontSize: 12 },
  likeBtn: { padding: 6 },
  reactions: { flexDirection: 'row', alignItems: 'center' },
  reactBtn: { paddingHorizontal: 8 }
});
